previewCss:
.darma-loader-darma-custom-420 {color: var(--loader-color, #f97316);
  --loader-secondary-color: #facc15;
  --loader-bg: #ffffff;
  width: 50px;
  aspect-ratio: 1;
  border: 2px solid;
  box-sizing: border-box;
  border-radius: 50%;
  display: grid;
  animation: darma-loader-darma-custom-420-l11 1.5s infinite linear;
  transform-origin: 50% 80%;
}.darma-loader-darma-custom-420:before,.darma-loader-darma-custom-420:after {content: "";
  grid-area: 1/1;
  border: inherit;
  border-radius: 50%;
  animation: inherit;
  animation-duration: 1s;
  transform-origin: inherit;
}.darma-loader-darma-custom-420:before {--s:-1;
}@keyframes darma-loader-darma-custom-420-l11 {100% {transform: scale(calc(var(--s,1)*1turn))}}

